CREATE TRIGGER [Equipment].[StateChange_History]ON [Equipment].[StateChange]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.StateChangeId IS NOT NULL AND d.StateChangeId IS NULL THEN 'I' 		WHEN i.StateChangeId IS NOT NULL AND d.StateChangeId IS NOT NULL THEN 'U' 		WHEN i.StateChangeId IS NULL AND d.StateChangeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.StateChangeId = d.StateChangeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Equipment_StateChange([StateChangeId], [EquipmentId], [EquipmentName], [StateChangeTime], [StateChangeTimeUTC], [CurrentStateId], [PreviousStateId], [PreviousStateTimeInSeconds], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUTC],[HistoryAction])	SELECT [StateChangeId], [EquipmentId], [EquipmentName], [StateChangeTime], [StateChangeTimeUTC], [CurrentStateId], [PreviousStateId], [PreviousStateTimeInSeconds], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUTC],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Equipment_StateChange([StateChangeId], [EquipmentId], [EquipmentName], [StateChangeTime], [StateChangeTimeUTC], [CurrentStateId], [PreviousStateId], [PreviousStateTimeInSeconds], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUTC],[HistoryAction])	SELECT [StateChangeId], [EquipmentId], [EquipmentName], [StateChangeTime], [StateChangeTimeUTC], [CurrentStateId], [PreviousStateId], [PreviousStateTimeInSeconds], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUTC],@HistoryAction  	FROM deletedEND